import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def travel_time(cur_pos, next_pos):
        return np.linalg.norm(cur_pos - next_pos) / truck_speed

    def is_within_window(arrival_time, window):
        start, end = window
        if arrival_time < start:
            return start - arrival_time, 0  # Early, must wait
        elif arrival_time > end:
            return 0, (arrival_time - end) * 10  # Late, high penalty
        else:
            return 0, 0  # On time, no penalty

    def fleet_idle_time(adjustment_weight):
        max_time = 0
        for truck_pos in all_truck_pos:
            dist_to_depot = np.linalg.norm(truck_pos - depot_pos)
            max_time = max(max_time, current_time + dist_to_depot / truck_speed)
        return adjustment_weight * (max_time - current_time)

    adjustment_weight = 0.2
    min_score = float('inf')
    best_node = None

    for i, customer in enumerate(unvisited_customers):
        time_to_customer = travel_time(cur_truck_pos, customer)
        projected_arrival = current_time + time_to_customer
        wait_penalty, late_penalty = is_within_window(projected_arrival, time_windows[i])
        adjustment_score = fleet_idle_time(adjustment_weight)

        total_score = wait_penalty + late_penalty + adjustment_score + time_to_customer

        if total_score < min_score:
            min_score = total_score
            best_node = i

    return best_node

